import{_ as a,a as t,b as n,c as o}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as r,o as d,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Magnet-transfer","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Other/magnet-transfer.md","filePath":"nl-NL/Other/magnet-transfer.md","lastUpdated":1781962217000}'),s={name:"nl-NL/Other/magnet-transfer.md"};function g(p,e,k,h,u,m){return d(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="magnet-transfer" tabindex="-1">Magnet-transfer <a class="header-anchor" href="#magnet-transfer" aria-label="Permalink to &quot;Magnet-transfer&quot;">​</a></h1><p>Magnet-transfer downloadt bestanden vanaf een magnetlink en uploadt ze automatisch naar het cloudopslagkanaal dat je kiest.</p><p>Dit is handig voor anime-afleveringen, video&#39;s, archieven en vergelijkbare bestanden. Plak een magnetlink en ImgBed maakt een downloadtaak op de achtergrond. Wanneer de download klaar is, wordt het bestand naar ImgBed geüpload en verschijnt de uiteindelijke link in de uploadlijst.</p><p><img src="'+a+'" alt="Magnet-transfer" loading="lazy"></p><h2 id="waar-je-dit-gebruikt" tabindex="-1">Waar je dit gebruikt <a class="header-anchor" href="#waar-je-dit-gebruikt" aria-label="Permalink to &quot;Waar je dit gebruikt&quot;">​</a></h2><p>De ingang voor magnet-transfer staat in het uploadgedeelte van de homepage.</p><p>Plak de magnetlink in het invoerveld, kies <code>Transfer</code> en upload.</p><p><img src="'+t+'" alt="Anime uploaden" loading="lazy"></p><h2 id="voor-het-eerste-gebruik" tabindex="-1">Voor het eerste gebruik <a class="header-anchor" href="#voor-het-eerste-gebruik" aria-label="Permalink to &quot;Voor het eerste gebruik&quot;">​</a></h2><p>Configureer magnet-transfer eerst in het beheerpaneel.</p><p>Meestal heb je nodig:</p><ol><li>Een GitHub-account om de downloadtaak uit te voeren.</li><li>Een cloud-uploadkanaal, zoals Google Drive of OneDrive.</li><li>De doelmap voor upload.</li><li>Een taak-time-out.</li></ol><p>Wanneer de instellingen klaar zijn, ga je terug naar de homepage en plak je een magnetlink om de transfer te starten.</p><h2 id="een-magnetlink-uploaden" tabindex="-1">Een magnetlink uploaden <a class="header-anchor" href="#een-magnetlink-uploaden" aria-label="Permalink to &quot;Een magnetlink uploaden&quot;">​</a></h2><ol><li>Plak de magnetlink in het uploadveld op de homepage.</li><li>Controleer dat de modus op <code>Transfer</code> staat.</li><li>Klik op upload.</li><li>Wacht tot ImgBed de magnettaak aanmaakt.</li><li>Zodra de taak start, gebruik je het zwevende paneel <code>Magnet Tasks</code> rechtsonder om de voortgang te volgen.</li></ol><p>Downloaden en uploaden kunnen tijd kosten. De snelheid hangt af van de magnetbron, de GitHub-runtimeomgeving en het gekozen cloudopslagkanaal.</p><p><img src="'+n+'" alt="Magnet wordt gedownload" loading="lazy"></p><h2 id="na-voltooiing" tabindex="-1">Na voltooiing <a class="header-anchor" href="#na-voltooiing" aria-label="Permalink to &quot;Na voltooiing&quot;">​</a></h2><p>Na afronding toont de uploadlijst de bestandsnaam en link.</p><p>Video&#39;s tonen een videopreview, afbeeldingen een afbeeldingspreview en andere bestanden een normaal bestandspictogram.</p><p><img src="'+o+'" alt="Gedownloade video" loading="lazy"></p><p>Je kunt kopiëren:</p><table tabindex="0"><thead><tr><th>Linktype</th><th>Gebruik</th></tr></thead><tbody><tr><td>Originele link</td><td>Directe bestandstoegang</td></tr><tr><td>Markdown</td><td>Markdown-berichten of notities</td></tr><tr><td>HTML</td><td>Webpaginacode</td></tr><tr><td>BBCode</td><td>Forums die BBCode ondersteunen</td></tr></tbody></table><h2 id="magnettakenpaneel" tabindex="-1">Magnettakenpaneel <a class="header-anchor" href="#magnettakenpaneel" aria-label="Permalink to &quot;Magnettakenpaneel&quot;">​</a></h2><p>Het paneel rechtsonder toont aantal taken, taaknaam, voortgang en eindstatus.</p><p>Veelvoorkomende statussen:</p><table tabindex="0"><thead><tr><th>Status</th><th>Betekenis</th></tr></thead><tbody><tr><td>Waiting</td><td>De taak is aangemaakt en wacht op uitvoering.</td></tr><tr><td>Downloading</td><td>De magnetbron wordt gedownload.</td></tr><tr><td>Uploading</td><td>Het bestand is gedownload en wordt naar cloudopslag geüpload.</td></tr><tr><td>Completed</td><td>Upload gelukt en de link kan worden gekopieerd.</td></tr><tr><td>Failed</td><td>De taak is niet succesvol afgerond. Controleer de melding en probeer opnieuw.</td></tr></tbody></table><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Bevat een magnetlink meerdere bestanden, dan geeft ImgBed prioriteit aan het belangrijkste afgeronde bestand voor weergave.</li><li>Grote bestanden duren langer. Wacht tot de taak klaar is voordat je de pagina ververst.</li><li>Heeft de magnetbron geen beschikbare peers, dan kan de download erg langzaam zijn of mislukken.</li><li>Is het cloudaccount vol, de autorisatie verlopen of de uploadmap verkeerd, dan kan de taak mislukken.</li><li>Videopreview kan enkele seconden nodig hebben nadat uploaden klaar is.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="er-start-niets-nadat-ik-een-magnetlink-plak" tabindex="-1">Er start niets nadat ik een magnetlink plak <a class="header-anchor" href="#er-start-niets-nadat-ik-een-magnetlink-plak" aria-label="Permalink to &quot;Er start niets nadat ik een magnetlink plak&quot;">​</a></h3><p>Controleer of magnet-transfer in het beheer is ingeschakeld en of een bruikbaar GitHub-account en cloudkanaal zijn geselecteerd.</p><h3 id="downloaden-is-altijd-traag" tabindex="-1">Downloaden is altijd traag <a class="header-anchor" href="#downloaden-is-altijd-traag" aria-label="Permalink to &quot;Downloaden is altijd traag&quot;">​</a></h3><p>Magnetsnelheid hangt af van de bron zelf. Zijn er geen beschikbare peers, dan kan downloaden heel traag of onmogelijk zijn.</p><h3 id="er-verschijnt-geen-preview-na-upload" tabindex="-1">Er verschijnt geen preview na upload <a class="header-anchor" href="#er-verschijnt-geen-preview-na-upload" aria-label="Permalink to &quot;Er verschijnt geen preview na upload&quot;">​</a></h3><p>Controleer eerst of de bestandslink opent. Videobestanden kunnen in de browser wat tijd nodig hebben om te laden, of je kunt de link direct openen.</p><h3 id="wat-controleer-ik-als-een-taak-mislukt" tabindex="-1">Wat controleer ik als een taak mislukt? <a class="header-anchor" href="#wat-controleer-ik-als-een-taak-mislukt" aria-label="Permalink to &quot;Wat controleer ik als een taak mislukt?&quot;">​</a></h3><p>Controleer of de magnetlink geldig is, of het cloudkanaal werkt en of de uploadmap klopt. Dien de taak daarna opnieuw in.</p>',38)])])}const v=r(s,[["render",g]]);export{f as __pageData,v as default};
